```typescript
  const getCoordinates = (e: MouseEvent | TouchEvent): {x: number; y: number} => {
    const canvas = canvasRef.current;
    if (!canvas) return {x: 0, y: 0};
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    if (e instanceof TouchEvent) {
      return {
        x:
          (e.touches[0].clientX - rect.left) * scaleX,
        y:
          (e.touches[0].clientY - rect.top) * scaleY,
      };
    } else {
      return {
        x:
          (e.offsetX || e.nativeEvent.offsetX || 0) * scaleX,
        y:
          (e.offsetY || e.nativeEvent.offsetY || 0) * scaleY,
      };
    }
  };
```

The function `getCoordinates` is now able to properly handle events of both the `MouseEvent` and `TouchEvent` types.

